function check_borrow_reverts_when_paused(address borrower, address position, uint256 amount) public {
    // Setup: pause the contract
    vm.prank(pauser);
    cdpVault.pause();

    // Precondition: contract is paused
    require(cdpVault.paused());

    // Action: attempt to borrow
    vm.prank(borrower);
    try cdpVault.borrow(borrower, position, amount) {
        // If borrow succeeds, the invariant is violated
        assert(false);
    } catch {
        // Expected: should revert when paused
        assert(true);
    }
}
